def strip_ansi_codes(text):
    """Remove ANSI color codes from a string."""
    ansiPattern = re.compile('\\033\\[[0-9;]*m')
    return ansiPattern.sub('', text)

def show_getting_mm_total(torsionTag):
    greenText = '\x1b[32m'
    redText = '\x1b[31m'
    orangeText = '\x1b[38;5;172m'
    yellowText = '\x1b[33m'
    resetTextColor = '\x1b[0m'
    tealText = '\x1b[38;5;37m'
    brightGreenText = '\x1b[92m'
    text = f"{yellowText}ūüó≤ūüó≤{resetTextColor}{' ' * 8}Fitting torsion parameters for {greenText}{torsionTag}"
    visibleText = strip_ansi_codes(text)
    nSpaces = 102 - len(visibleText) - 3
    text += f"{' ' * nSpaces}{yellowText}ūüó≤ūüó≤{resetTextColor}"
    sys.stdout.write('\r\x1b[K' + text)
    sys.stdout.flush()

