def show_torsion_being_scanned(torsionTag, torsionIndex, nTorsions) -> None:
    greenText = '\x1b[32m'
    redText = '\x1b[31m'
    orangeText = '\x1b[38;5;172m'
    yellowText = '\x1b[33m'
    resetTextColor = '\x1b[0m'
    tealText = '\x1b[38;5;37m'
    textToPrint = f"{yellowText}ūüó≤ ūüó≤{' ' * 8}SCANNING TORSION:{' ' * 8}[{' ' * 1}{greenText}{torsionTag}{yellowText}{' ' * 1}]{' ' * 8}{resetTextColor}({torsionIndex + 1}/{nTorsions}){yellowText}"
    visibleText = strip_ansi_codes(textToPrint)
    nSpaces = 124 - len(visibleText) - 3
    textToPrint += f"{' ' * nSpaces}{yellowText}ūüó≤ūüó≤{resetTextColor}"
    print(textToPrint)

