    def clear_terminal():
        os.system('cls' if os.name == 'nt' else 'clear')
    duration = 3
    framesPerSecond = 60
    totalFrames = duration * framesPerSecond
    maxShift = 2
    greenText = '\x1b[32m'
    resetColor = '\x1b[0m'
    for frame in range(totalFrames):
        clear_terminal()
        import math
        shift = int(maxShift * math.sin(frame * 0.5))
        for line in art:
            padding = ' ' * (maxShift + shift)
            print(f'{padding}{greenText}{line}{resetColor}')
        time.sleep(1 / framesPerSecond)
    clear_terminal()
    for line in art:
        print(f"{' ' * maxShift}{greenText}{line}{resetColor}")
    yellowText = '\x1b[33m'
    resetTextColor = '\x1b[0m'
    print(' ' * 16 + yellowText + f'{forcefield} PARAMETERS FOR YOUR MOLECULE:' + ' ' * 4 + greenText + moleculeName + resetTextColor)
    print()
    print(' ' * 16 + yellowText + f'VIEW REPORT AT:\n' + ' ' * 4 + f'{greenText}{reportHtml}{resetTextColor}')

